function solve(n, m, k) {
    if (k === 0) return n * m;
    if (n === 1 && m === 1) return 1;
    if (k >= Math.min(n, m) / 2) return 1;

    let rows = Math.ceil((n + 2 * k - 1) / (2 * k));
    let cols = Math.ceil((m + 2 * k - 1) / (2 * k));
    return rows * cols;
}
